import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';

const Dashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    totalTasks: 0,
    pendingApplications: 0,
    approvedShifts: 0,
    totalEmployees: 0,
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const statsRes = await api.get('/dashboard/stats');
      setStats(statsRes.data);
    } catch (error) {
      console.error('Failed to fetch dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '400px' }}>
        <div style={{ width: '40px', height: '40px', border: '3px solid #00d1ff', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
      </div>
    );
  }

  return (
    <div style={{ padding: '20px', fontFamily: 'Inter, sans-serif' }}>
      <h1 style={{ fontSize: '2rem', marginBottom: '0.5rem', color: 'white' }}>
        Welcome back, <span style={{ color: '#00d1ff' }}>{user?.name}</span>!
      </h1>
      <p style={{ color: '#aaa', marginBottom: '2rem' }}>Here's an overview of your business</p>
      
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1.5rem', marginBottom: '2rem' }}>
        <div style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '1rem', padding: '1.5rem' }}>
          <div style={{ color: '#00d1ff', fontSize: '0.9rem', marginBottom: '0.5rem' }}>TOTAL TASKS</div>
          <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'white' }}>{stats.totalTasks}</div>
        </div>
        
        <div style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '1rem', padding: '1.5rem' }}>
          <div style={{ color: '#f59e0b', fontSize: '0.9rem', marginBottom: '0.5rem' }}>PENDING APPLICATIONS</div>
          <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'white' }}>{stats.pendingApplications}</div>
        </div>
        
        <div style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '1rem', padding: '1.5rem' }}>
          <div style={{ color: '#10b981', fontSize: '0.9rem', marginBottom: '0.5rem' }}>APPROVED SHIFTS</div>
          <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'white' }}>{stats.approvedShifts}</div>
        </div>
        
        <div style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '1rem', padding: '1.5rem' }}>
          <div style={{ color: '#ef4444', fontSize: '0.9rem', marginBottom: '0.5rem' }}>TOTAL EMPLOYEES</div>
          <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'white' }}>{stats.totalEmployees}</div>
        </div>
      </div>
      
      <div style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '1rem', padding: '1.5rem', marginBottom: '2rem' }}>
        <h3 style={{ color: 'white', marginBottom: '1rem' }}>Quick Actions</h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '1rem' }}>
          <button onClick={() => window.location.href = '/#/tasks'} style={{ background: 'rgba(0,209,255,0.1)', border: '1px solid #00d1ff', borderRadius: '0.5rem', padding: '0.75rem', color: '#00d1ff', cursor: 'pointer' }}>Create Task</button>
          <button onClick={() => window.location.href = '/#/employees'} style={{ background: 'rgba(0,209,255,0.1)', border: '1px solid #00d1ff', borderRadius: '0.5rem', padding: '0.75rem', color: '#00d1ff', cursor: 'pointer' }}>Add Employee</button>
          <button onClick={() => window.location.href = '/#/calendar'} style={{ background: 'rgba(0,209,255,0.1)', border: '1px solid #00d1ff', borderRadius: '0.5rem', padding: '0.75rem', color: '#00d1ff', cursor: 'pointer' }}>View Calendar</button>
          <button onClick={() => window.location.href = '/#/profile'} style={{ background: 'rgba(0,209,255,0.1)', border: '1px solid #00d1ff', borderRadius: '0.5rem', padding: '0.75rem', color: '#00d1ff', cursor: 'pointer' }}>My Profile</button>
        </div>
      </div>
      
      <style>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default Dashboard;